#include <bits/stdc++.h>
using namespace std;
int di[4][2]={{0,1},{0,-1},{1,0},{-1,0}};
int n,m,a[502][502],mark[502][502],sum,l,r,u,d;
set<string> ans;
void paint(int x,int y){
	mark[x][y]=sum;
	l=min(l,y),r=max(r,y),u=min(u,x),d=max(d,x);
	for(int i=0;i<4;i++){
		int xx=x+di[i][0],yy=y+di[i][1];
		if(xx>0 && yy>0 && xx<=n && yy<=m && !mark[xx][yy] && a[xx][yy]==a[x][y])
			paint(xx,yy);
	}
}
int main(){
	cin>>n>>m;
	for(int i=1;i<=n;i++)
		for(int j=1;j<=m;j++)
			cin>>a[i][j];
	for(int i=1;i<=n;i++)
		for(int j=1;j<=m;j++){
			if(mark[i][j])
				continue;
			l=r=j,u=d=i;
			++sum;
			paint(i,j);
			string s;
			for(int x=u;x<=d;x++){
				for(int y=l;y<=r;y++)
					if(mark[x][y]==sum)
						s+='#';
					else
						s+='.';
				s+='n';
			}
			//cout<<s<<endl;
			ans.insert(s);
		}
	cout<<ans.size();
	return 0; 
}
